// Собираем факт расходов по проекту из разных DocType:
// 1. Закупки (Purchase Invoice)
// 2. КС-2 от субподрядчиков (через Purchase Invoice с subcontract)
// 3. Зарплата работников, аллоцированная на проект
// 4. Прочие расходы (Journal Entry)

const project = $input.first().json;

return [{
  json: {
    erpnext_project: project.name,
    oce_project_id: project.custom_oce_project_id,
    oce_boq_id: project.custom_oce_boq_id,
    budget: project.estimated_costing,
    queries: {
      purchase_invoices: {
        url: 'http://erpnext-backend:8000/api/resource/Purchase Invoice',
        filters: JSON.stringify([['project', '=', project.name], ['docstatus', '=', 1]])
      },
      timesheets: {
        url: 'http://erpnext-backend:8000/api/resource/Timesheet',
        filters: JSON.stringify([['parent_project', '=', project.name], ['docstatus', '=', 1]])
      },
      journal_entries: {
        url: 'http://erpnext-backend:8000/api/resource/Journal Entry Account',
        filters: JSON.stringify([['project', '=', project.name], ['docstatus', '=', 1]])
      }
    }
  }
}];

// Агрегация факта для EVM-расчёта
const projectData = $('Build Actuals Queries').first().json;
const purchases = $('Fetch Purchase Invoices').first().json.data || [];
const timesheets = $('Fetch Timesheets').first().json.data || [];

const actualCost = 
  purchases.reduce((sum, pi) => sum + (pi.grand_total || 0), 0) +
  timesheets.reduce((sum, ts) => sum + (ts.total_billable_amount || 0), 0);

// Определяем процент готовности по последней дате
const allDates = [
  ...purchases.map(p => new Date(p.posting_date)),
  ...timesheets.map(t => new Date(t.start_date))
];
const lastActivity = allDates.length > 0 ? new Date(Math.max(...allDates)) : new Date();

return [{
  json: {
    oce_project_id: projectData.oce_project_id,
    oce_boq_id: projectData.oce_boq_id,
    report_date: new Date().toISOString().split('T')[0],
    actual_cost: actualCost,
    actual_cost_by_source: {
      purchases: purchases.reduce((sum, pi) => sum + pi.grand_total, 0),
      labor: timesheets.reduce((sum, ts) => sum + ts.total_billable_amount, 0)
    },
    transactions_count: purchases.length + timesheets.length,
    last_activity_date: lastActivity.toISOString().split('T')[0],
    budget: projectData.budget,
    burn_rate_percent: (actualCost / projectData.budget) * 100
  }
}];

